<script setup>
import BaseView from '@/components/base/BaseView';
const { onMounted, ref, t, btnSearch, btnDelete, onUnmounted } = BaseView();
import { watchEffect, computed } from 'vue';

import { useCommonCodeStore } from '@/stores/commonCode';
const commonCodeStore = useCommonCodeStore();

import CodePopup from '@/views/system/setting/CommonCodePopup.vue';

import { OverlayScrollbarsComponent } from 'overlayscrollbars-vue';

const gridMaster = ref(null);
const gridDetail = ref(null);
const dialogGroup = ref(null);
const gridPageMaster = ref(null);
const gridPageDetail = ref(null);

import { useButtonListStore } from '@/stores/buttonList';
const layoutStore = useButtonListStore();
layoutStore.useBtnList = ['btnSearch', 'btnDelete'];

btnSearch(() => {
    commonCodeStore.searchSystemCodeGrid(true);
});
btnDelete(() => {
    commonCodeStore.deleteCode();
});

onMounted(async () => {
    commonCodeStore.searchSystemCodeGrid(true);
    commonCodeStore.setRefs(gridMaster, gridDetail, dialogGroup, gridPageMaster, gridPageDetail);
});

// 화면 확대 축소 일 때, height 리사이징
const devicePixelRatio = ref(window.devicePixelRatio);
const isZoomed = computed(() => devicePixelRatio.value > 1);
const updatePixelRatio = () => {
    devicePixelRatio.value = window.devicePixelRatio;
};
onMounted(() => {
    window.addEventListener('resize', updatePixelRatio);
});
onUnmounted(() => {
    window.removeEventListener('resize', updatePixelRatio);
});
watchEffect(() => {
    updatePixelRatio();
});
</script>
